head.script:
/**
 * 화 면 명 : 클래스별 자산현황
 * 메뉴경로 : 회계/재무회계/고정자산/지사별자산현황
 * ASIS경로 : /debis/dongwon-debis-engine/src/main/webapp/ac/fi/fixedaset/fi_301_02_10p.jsp
 * 작 성 자 : 배기원
 * 작 업 일 : 2025-10-24
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 *    5. footer에 값 처리
 * 참고사항 : 
 *    1. 그리드ID.setNoResultMessageVisible(false) 설정해줘야 그리드에 데이터없음 안보임
 *    2. "hiddenVisible":true 되어 있는 항목 일단 false 처리[hiddenCol="true" => hiddenCol="false"]
 * 수정이력 :
 *    - 2025-11-10      배기원    최초작성
 */
//로그인 정보
scwin.memJson;
scwin.vLoginCoCd;   
scwin.vLoginCoClsCd;
scwin.vUserHomeClsCd;

//파라메터 정보
scwin.valueObject;
scwin.vCloseYm       = ""; //기준년월
scwin.vAcctDeptCd    = ""; //부서코드
scwin.vAcctDeptNm    = ""; //부서명

/**
 * TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
 */
scwin.onpageload = function() {
    scwin.memJson = $c.data.getMemInfo();
    scwin.vLoginCoCd     = $c.gus.cfIsNull(scwin.memJson["coCd"]) ? "" : scwin.memJson["coCd"];                   //소속자회사
    scwin.vLoginCoClsCd  = $c.gus.cfIsNull(scwin.memJson["coClsCd"]) ? "" : scwin.memJson["coClsCd"];             //회계_회사구분('CO035' : 0:동부 EXPRESS)
    scwin.vUserHomeClsCd = $c.gus.cfIsNull(scwin.memJson["userHomeClsCd"]) ? "" : scwin.memJson["userHomeClsCd"]; //사용자소속구분코드
    scwin.valueObject = $c.data.getParameter();

    if (!$c.util.isEmpty(scwin.valueObject["pCloseYm"])) {
        scwin.vCloseYm = scwin.valueObject["pCloseYm"];
    }
    if (!$c.util.isEmpty(scwin.valueObject["pAcctDeptCd"])) {
        scwin.vAcctDeptCd = scwin.valueObject["pAcctDeptCd"];
    }
    if (!$c.util.isEmpty(scwin.valueObject["pAcctDeptNm"])) {
        scwin.vAcctDeptNm = scwin.valueObject["pAcctDeptNm"];
    }
};

/**
 * 초기세팅(TOBE 그리드, 총건수)
 */
scwin.setInit = function() {
    ed_acctDeptCd.hidVal = "";  //부서(조회)
    gr_master.setNoResultMessageVisible(false);
    ds_master.reform();
    ds_master.removeAll();
    totalRows.setValue("0");
};

/**
 * UDC값 초기화(scwin.onpageload 이후 세팅됨)
 */
scwin.onUdcCompleted = function() {
    scwin.setInit();
    ica_closeYm.setValue(scwin.vCloseYm);
    ed_acctDeptCd.setValue(scwin.vAcctDeptCd);
    ed_acctDeptNm.setValue(scwin.vAcctDeptNm);
    lc_unit.setValue("1");
    scwin.f_Retrieve();
};

/**
 * 헤더생성
 * asis : 사용안함
 */
